```class Solution {
    public int findNthDigit(int n) {
        long count = 1;
        long digits = 1;
        long start = 1;
        while (n > digits * count) {
            n -= digits * count;
            count *= 10;
            digits++;
            start *= 10;
        }
        start += (n - 1) / digits;
        String s = String.valueOf(start);
        return Integer.parseInt(String.valueOf(s.charAt((n - 1) % digits)));
    }
}```
